    27→import { Upload as Upload, Palette as Palette, Info as Info, Loader2 as Loader2 } from "lucide-react";
    28→import { toast } from "sonner";
    29→import { salonService } from "@/services/salonService";
    30→import { cepService } from "@/services/cepService";
    31→import { Salon, UpdateSalonDto } from "@/types/salon";
    32→import { formatPhone } from "@/utils/formatters";
    33→
    34→interface SalonInfo {
    35→  nomeFantasia: string;
    36→  razaoSocial: string;
    37→  cnpj: string;
    38→  telefoneComercial: string;
    39→  emailContato: string;
    40→  nomeLinkUtil: string;
    41→  urlLinkUtil: string;
    42→  timezone: string;
    43→}
