     8→import { Loader2 as Loader2 } from "lucide-react";
     9→import { toast } from "sonner";
    10→
    11→interface ServiceData {
    12→  name: string;
    13→  acceptsOnlineBooking?: boolean;
    14→  price?: number | string;
    15→  duration?: number;
    16→  commission?: number | string;
    17→}
    18→
    19→interface ServiceFormProps {
    20→  initialData?: ServiceData;
    21→  onSave: (data: ServiceData) => void;
    22→  onCancel: () => void;
    23→  isEditing?: boolean;
    24→  isSaving?: boolean;
    25→  isCustomService?: boolean;
    26→  disabledActions?: boolean;
    27→}
    28→
    29→export function ServiceForm({
    30→  initialData,
    31→  onSave,
    32→  onCancel,
    33→  isEditing = false,
    34→  isSaving = false,
    35→  isCustomService = false,
    36→  disabledActions,
    37→}: ServiceFormProps) {
    38→  // Format initial values for masked inputs
    39→  const formatInitialPrice = (price?: number | string): string => {
    40→    if (!price) return "0,00";
    41→    const numValue =
    42→      typeof price === "string" ? parseFloat(price.replace(",", ".")) : price;
    43→    return numValue.toFixed(2).replace(".", ",");
    44→  };
    45→
    46→  const formatInitialCommission = (commission?: number | string): string => {
    47→    if (!commission) return "0,00";
    48→    const numValue =
    49→      typeof commission === "string"
    50→        ? parseFloat(commission.replace(",", "."))
    51→        : commission;
    52→    return numValue.toFixed(2).replace(".", ",");
    53→  };
    54→
    55→  const [serviceData, setServiceData] = useState<ServiceData>({
    56→    name: initialData?.name || "",
    57→    acceptsOnlineBooking: initialData?.acceptsOnlineBooking ?? true,
    58→    price: formatInitialPrice(initialData?.price),
    59→    duration: initialData?.duration || 30,
    60→    commission: formatInitialCommission(initialData?.commission),
    61→  });
    62→
    63→  const [errors, setErrors] = useState<
    64→    Partial<Record<keyof ServiceData, string>>
    65→  >({});
    66→
    67→  const handleInputChange = (
    68→    e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>
    69→  ) => {
    70→    const { name, value, type } = e.target;
    71→
    72→    setServiceData((prev) => ({
    73→      ...prev,
    74→      [name]: type === "number" ? (value === "" ? 0 : Number(value)) : value,
    75→    }));
    76→
    77→    // Clear error when user starts typing
    78→    if (errors[name as keyof ServiceData]) {
    79→      setErrors((prev) => ({ ...prev, [name]: undefined }));
    80→    }
    81→  };
    82→
    83→  const validateForm = (): boolean => {
    84→    const newErrors: Partial<Record<keyof ServiceData, string>> = {};
    85→
    86→    // Validate name: Required, min 2 characters, max 100 characters
    87→    if (!serviceData.name.trim()) {
    88→      newErrors.name = "Nome é obrigatório";
    89→    } else if (serviceData.name.trim().length < 2) {
    90→      newErrors.name = "Nome deve ter pelo menos 2 caracteres";
    91→    } else if (serviceData.name.length > 100) {
    92→      newErrors.name = "Nome não pode ter mais de 100 caracteres";
    93→    }
    94→
    95→    // Validate price, duration, and commission for custom services
    96→    if (isCustomService) {
    97→      const priceValue =
    98→        typeof serviceData.price === "string"
    99→          ? parseFloat(serviceData.price.replace(".", "").replace(",", "."))
   100→          : serviceData.price;
   101→
   102→      const commissionValue =
   103→        typeof serviceData.commission === "string"
   104→          ? parseFloat(serviceData.commission.replace(",", "."))
   105→          : serviceData.commission;
   106→
   107→      if (priceValue !== undefined && priceValue <= 0) {
   108→        newErrors.price = "Preço deve ser maior que zero";
   109→      }
   110→      if (serviceData.duration !== undefined && serviceData.duration < 1) {
   111→        newErrors.duration = "Duração deve ser pelo menos 1 minuto";
   112→      }
   113→      if (
   114→        commissionValue !== undefined &&
   115→        (commissionValue < 0 || commissionValue > 100)
   116→      ) {
   117→        newErrors.commission = "Comissão deve estar entre 0% e 100%";
   118→      }
   119→    }
   120→
   121→    setErrors(newErrors);
   122→
   123→    if (Object.keys(newErrors).length > 0) {
   124→      const firstError = Object.values(newErrors)[0];
   125→      toast.error(firstError);
   126→      return false;
   127→    }
   128→
   129→    return true;
   130→  };
   131→
   132→  const handleSubmit = (e: React.FormEvent) => {
   133→    e.preventDefault();
   134→
   135→    if (!validateForm()) {
   136→      return;
   137→    }
   138→
   139→    // Convert masked values to numbers before saving
   140→    const dataToSave = {
   141→      ...serviceData,
   142→      price:
   143→        typeof serviceData.price === "string"
   144→          ? parseFloat(serviceData.price.replace(".", "").replace(",", "."))
   145→          : serviceData.price,
   146→      commission:
   147→        typeof serviceData.commission === "string"
   148→          ? parseFloat(serviceData.commission.replace(",", "."))
   149→          : serviceData.commission,
   150→    };
   151→
   152→    onSave(dataToSave);
   153→  };
   154→
   155→  return (
   156→    <form onSubmit={handleSubmit} className="flex-1 flex flex-col overflow-hidden">
   157→      <div className="flex-1 overflow-y-auto px-6 py-4 custom-scrollbar space-y-4">
   158→        <div className="space-y-2">
   159→          <Label htmlFor="name">Nome do Serviço *</Label>
   160→          <Input
   161→            id="name"
   162→            name="name"
   163→            type="text"
   164→            value={serviceData.name}
   165→            onChange={handleInputChange}
   166→            placeholder="Digite o nome do serviço"
   167→            required
   168→            disabled={isSaving}
   169→            maxLength={100}
   170→            className={errors.name ? "border-red-500" : ""}
   171→          />
   172→          {errors.name && <p className="text-sm text-red-500">{errors.name}</p>}
   173→          <p className="text-sm text-muted-foreground">
   174→            Mínimo 2 caracteres, máximo 100 caracteres
   175→          </p>
   176→        </div>
   177→
   178→        {/* Show price, duration, and commission fields for custom services */}
   179→        {isCustomService && (
   180→          <>
   181→            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
   182→              <div className="space-y-2">
   183→                <Label htmlFor="price">Preço *</Label>
   184→                <CurrencyInput
   185→                  id="price"
   186→                  value={serviceData.price as string}
   187→                  onChange={(value) =>
   188→                    setServiceData((prev) => ({ ...prev, price: value }))
   189→                  }
   190→                  disabled={isSaving}
   191→                  className={errors.price ? "border-red-500" : ""}
   192→                  placeholder="Ex: R$ 50,00"
   193→                />
   194→              </div>
   195→
   196→              <div className="space-y-2">
   197→                <Label htmlFor="duration">Duração (minutos)</Label>
   198→                <Input
   199→                  id="duration"
   200→                  name="duration"
   201→                  type="number"
   202→                  min="15"
   203→                  step={15}
   204→                  value={serviceData.duration || ""}
   205→                  onChange={handleInputChange}
   206→                  placeholder="30"
   207→                  disabled={isSaving}
   208→                  className={errors.duration ? "border-red-500" : ""}
   209→                />
   210→                {errors.duration && (
   211→                  <p className="text-sm text-red-500">{errors.duration}</p>
   212→                )}
   213→              </div>
   214→            </div>
   215→
   216→            <div className="space-y-2">
   217→              <Label htmlFor="commission">Comissão (%)</Label>
   218→              <PercentageInput
   219→                id="commission"
   220→                value={serviceData.commission as string}
   221→                onChange={(value) =>
   222→                  setServiceData((prev) => ({ ...prev, commission: value }))
   223→                }
   224→                disabled={isSaving}
   225→                className={errors.commission ? "border-red-500" : ""}
   226→              />
   227→              {errors.commission && (
   228→                <p className="text-sm text-red-500">{errors.commission}</p>
   229→              )}
   230→            </div>
   231→          </>
