    13→export function StepServices({ form }: StepServicesProps) {
    14→    const { control, register, watch } = form;
    15→
    16→    // Use useFieldArray for better performance when handling list of items
    17→    const { fields, replace, update } = useFieldArray({
    18→        control,
    19→        name: "services",
    20→    });
    21→
    22→    // Load services only if form is empty (persistence check)
    23→    useEffect(() => {
    24→        if (fields.length > 0) return;
    25→
    26→        const loadServices = async () => {
    27→            try {
    28→                const services = await onboardingService.getSuggestedServices();
    29→                const formattedServices = services.map((s) => ({
    30→                    serviceId: s.id,
    31→                    name: s.name,
    32→                    selected: false,
    33→                    price: s.defaultPrice,
    34→                    duration: s.defaultDuration,
    35→                }));
    36→                replace(formattedServices);
    37→            } catch (error) {
    38→                toast.error("Erro ao carregar serviços sugeridos");
    39→            }
    40→        };
    41→        loadServices();
    42→    }, [replace, fields.length]);
    43→
    44→    return (
    45→        <div className="space-y-6 animate-fade-in">
    46→            <div className="text-center mb-8">
    47→                <h1 className="font-semibold text-foreground mb-2 text-lg">
