    54→
    55→            <div className="space-y-4 max-w-lg mx-auto">
    56→
    57→                {fields.map((field, index) => {
    58→                    // We use watch inside the map? 
    59→                    // Better performance: The inputs inside use 'register' which handles changes.
    60→                    // But we need to conditionally render the expanded part.
    61→                    // Using a separate component for each Item is the best way to isolate re-renders with useWatch/watch.
    62→                    return (
    63→                        <ServiceItem
    64→                            key={field.id}
