    82→                </p>
    83→            )}
    84→
    85→
    86→        </div>
    87→    );
    88→}
    89→
    90→// Extracted for performance (isolates watch scope)
    91→function ServiceItem({ index, form, field }: { index: number; form: UseFormReturn<StepServicesData>; field: any }) {
    92→    const isSelected = form.watch(`services.${index}.selected`);
    93→
    94→    return (
    95→        <div className="border border-border overflow-hidden rounded-3xl transition-all duration-200">
    96→            <button
    97→                type="button"
    98→                onClick={async () => {
    99→                    form.setValue(`services.${index}.selected`, !isSelected);
   100→                    await form.trigger();
