   111→                >
   112→                    {isSelected && <Check className="w-4 h-4 text-white" />}
   113→                </div>
   114→                {/* Hidden input to register the boolean value */}
   115→                <input type="hidden" {...form.register(`services.${index}.selected`)} />
   116→            </button>
   117→
   118→            {isSelected && (
   119→                <div className="px-4 pb-4 pt-2 border-t border-border bg-muted/30 animate-in slide-in-from-top-2">
   120→                    <div className="grid grid-cols-2 gap-4">
