   127→                                type="number"
   128→                                step="0.01"
   129→                                inputMode="decimal"
   130→                                {...form.register(`services.${index}.price`, { valueAsNumber: true })}
   131→                            />
   132→                        </div>
   133→                        <div>
   134→                            <label className="block text-xs font-medium text-muted-foreground mb-1 flex items-center gap-1">
   135→                                <Clock className="w-3 h-3" /> Duração (min)
